import { EventEmitter } from 'events';

// Define an interface for the user data
interface User {
  id: number;
  name: string;
  email: string;
}

// Create a new event emitter instance
const eventEmitter = new EventEmitter();

// Listen for 'userSignedUp' event
eventEmitter.on('userSignedUp', (user: User) => {
  console.log(`New user signed up: ${user.name} (${user.email})`);
  // Here you can execute additional logic, like sending a welcome email
});

// Function to simulate user signup and emit event
function signUpUser(user: User) {
  // Simulate saving user to database
  console.log(`Saving user ${user.name} to the database.`);
  // Emit the event when the user signs up
  eventEmitter.emit('userSignedUp', user);
}

// Example usage
const newUser: User = { id: 1, name: 'Alice', email: 'alice@example.com' };
signUpUser(newUser);

type EventHandler<T> = (payload: T) => void;

class EventBus {
  private emitter = new EventEmitter();

  public subscribe<T>(eventName: string, handler: EventHandler<T>) {
    this.emitter.on(eventName, handler);
  }

  public publish<T>(eventName: string, payload: T) {
    this.emitter.emit(eventName, payload);
  }
}

// Usage example
interface Order {
  orderId: number;
  userId: number;
  product: string;
}

const eventBus = new EventBus();

// Subscriber
eventBus.subscribe<Order>('orderPlaced', (order) => {
  console.log(`Order placed: #${order.orderId} for product ${order.product}`);
  // Additional business logic here
});

// Publisher
function placeOrder(order: Order) {
  console.log(`Placing order #${order.orderId}`);
  eventBus.publish('orderPlaced', order);
}

const newOrder: Order = { orderId: 101, userId: 1, product: 'Book' };
placeOrder(newOrder);

class BaseError extends Error {
  public readonly code: string;
  public readonly metadata?: Record<string, any>;

  constructor(message: string, code: string, metadata?: Record<string, any>) {
    super(message);
    this.code = code;
    this.metadata = metadata;
    // Set the prototype explicitly to maintain instanceof checks
    Object.setPrototypeOf(this, new.target.prototype);
  }
}

class NetworkError extends BaseError {
  constructor(message: string, metadata?: Record<string, any>) {
    super(message, 'NETWORK_ERROR', metadata);
  }
}

class ValidationError extends BaseError {
  constructor(message: string, metadata?: Record<string, any>) {
    super(message, 'VALIDATION_ERROR', metadata);
  }
}

class DatabaseError extends BaseError {
  constructor(message: string, metadata?: Record<string, any>) {
    super(message, 'DATABASE_ERROR', metadata);
  }
}

import { Request, Response, NextFunction } from 'express';

function errorHandler(err: BaseError, req: Request, res: Response, next: NextFunction) {
  console.error(`[${err.code}] - ${err.message}`, err.metadata);

  const statusMap: Record<string, number> = {
    VALIDATION_ERROR: 400,
    NETWORK_ERROR: 503,
    DATABASE_ERROR: 500,
  };

  const status = statusMap[err.code] || 500;

  res.status(status).json({
    error: {
      code: err.code,
      message: err.message,
      metadata: err.metadata,
    },
  });
}

export default errorHandler;

interface ErrorResponse {
  code: string;
  message: string;
  metadata?: Record<string, any>;
}

// Example service response handler
async function fetchData(): Promise<void> {
  try {
    const response = await fetch('http://otherservice/api');
    if (!response.ok) {
      const errorBody: ErrorResponse = await response.json();
      throw new BaseError(errorBody.message, errorBody.code, errorBody.metadata);
    }
    // process data
  } catch (err) {
    if (err instanceof BaseError) {
      // Handle known errors
      console.log(`Handled error code: ${err.code}`);
    } else {
      // Handle unexpected errors
      console.error('Unexpected error', err);
    }
  }
}

